% Richard Foster and Cheng Ly
% Code calculates the CDF and Kolmogorov-Smirnov statistic that describes how well 
% the OKS firing rates fit the observed spike train, assuming the spikes were generated by an inhomogeneous Poisson process

clear;
close all;

typename='Cntr'; % Experiment type (healthy, PD)
varname='Gpe'; % Neuron type (GPe, GPi, STN)
filename='gpe'; 

data=load([filename 'data.mat'],['isi' typename 'SpkT' varname],['isi' typename varname]);
fn=fieldnames(data);
all_spkTms=data.(fn{1}); % Load all spike times (in milliseconds)
all_isi=data.(fn{2}); % Load all interspike intervals (in milliseconds)

load([typename varname '_FinalResults.mat']); % Load OKS final results
n_exps=length(all_spkTms); % Number of experiments within a neuron type/condition

fs=1e5; % Sampling frequency from firing rate
tbin=1/fs; % Time bin, in seconds

for ii = 1:n_exps
    isi=all_isi{ii}/1000; % Extract interspike intervals (in seconds)
    spkTms=all_spkTms{ii}/1000; % Extract spike times (in seconds)
    
    h_opt=results(ii).Width; % Extract OKS bandwidth
    endTime=spkTms(end); % End of experiment (in seconds)
    [t_cont,lambda_cont] = gauss_kern(spkTms,h_opt,endTime,tbin); % Calculate OKS firing rate with fine temporal resolution
    [U,  KS_stat] = get_TRT(spkTms, t_cont, lambda_cont); % Calculate cumulative distribution function and kolmogorov-smirnov statistic 

    results(ii).CDF=U; % Save information
    results(ii).KS_stat=KS_stat; % Save information
end

save([typename varname '_FinalResults.mat'],"results",'-v7.3'); % Save data structure, append to final 